import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"资金退款","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/refund.md","filePath":"zh-CN/withdrawal/refund.md"}'),t={name:"withdrawal/refund.md"};function o(h,a,d,n,u,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="资金退款" tabindex="-1">资金退款 <a class="header-anchor" href="#资金退款" aria-label="Permalink to &quot;资金退款&quot;">​</a></h1><p>资金原路退回的触发场景、所需信息、退款时效及注意事项。</p><h2 id="退款触发场景" tabindex="-1">退款触发场景 <a class="header-anchor" href="#退款触发场景" aria-label="Permalink to &quot;退款触发场景&quot;">​</a></h2><p>以下情况可能需要资金原路退回：</p><ul><li>开户申请被拒绝或主动终止开户</li><li>银行卡未绑定成功但已入金</li><li>使用非本人银行卡（第三方）入金</li><li>使用信用卡入金</li><li>使用不支持的银行卡（如内地银行卡、非 FATF 成员国银行卡）入金</li></ul><h2 id="退款所需信息" tabindex="-1">退款所需信息 <a class="header-anchor" href="#退款所需信息" aria-label="Permalink to &quot;退款所需信息&quot;">​</a></h2><p>如需申请退款，请联系客服并提供以下信息：</p><ul><li>汇款银行账户号</li><li>银行卡名称及银行代码</li><li>汇款人名称</li></ul><h2 id="退款时效" tabindex="-1">退款时效 <a class="header-anchor" href="#退款时效" aria-label="Permalink to &quot;退款时效&quot;">​</a></h2><h3 id="长桥香港" tabindex="-1">长桥香港 <a class="header-anchor" href="#长桥香港" aria-label="Permalink to &quot;长桥香港&quot;">​</a></h3><p>香港银行卡退款：预计 1-3 个工作日<br> 非香港银行卡、第三方平台、信用卡退款：预计 5-10 个工作日</p><h3 id="长桥新加坡" tabindex="-1">长桥新加坡 <a class="header-anchor" href="#长桥新加坡" aria-label="Permalink to &quot;长桥新加坡&quot;">​</a></h3><p>以实际到账为准</p><p>退款需双方银行共同操作处理，时间会较长。</p><h2 id="原路退款说明与跨境费用" tabindex="-1">原路退款说明与跨境费用 <a class="header-anchor" href="#原路退款说明与跨境费用" aria-label="Permalink to &quot;原路退款说明与跨境费用&quot;">​</a></h2><ul><li>退款为原路退回，退回至原汇款账户</li><li>跨境电汇退款可能产生银行手续费，相关费用由客户自行承担</li><li>如汇款显示为中转行账户而非本人汇款账户，可能需要提供银行账单协助核对</li><li>如银行账单中查询不到入金信息，说明长桥尚未收到资金，建议咨询汇款银行定位资金动向</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/withdrawal">出金</a></li></ul>',18)])])}const f=e(t,[["render",o]]);export{p as __pageData,f as default};
